Patch Set 6:

fwiw, the following additional patch seems to fix the build:

--- a/lustre/osd-ldiskfs/osd_io.c
+++ b/lustre/osd-ldiskfs/osd_io.c
@@ -181,8 +181,13 @@ static void dio_complete_routine(struct bio *bio, int error
        if (!test_bit(__REQ_WRITE, &bio->bi_rw)) {
                bio_for_each_segment(bvl, bio, iter) {
                        if (likely(error == 0))
+#ifdef HAVE_BVEC_ITER
+                               SetPageUptodate(bvec_iter_page(&bvl, iter));
+                       LASSERT(PageLocked(bvec_iter_page(&bvl, iter)));
+#else
                                SetPageUptodate(bvec_iter_page(bvl, iter));
                        LASSERT(PageLocked(bvec_iter_page(bvl, iter)));
+#endif
                }
                atomic_dec(&iobuf->dr_dev->od_r_in_flight);
        } else {


I don't claim this is a good solution, only that it works.
